+    );
+
+    // Test with color parsing from rich_rust
+    use rich_rust::Color;
+
+    {
+        let _parse = test_phase("color_parsing");
+
+        // Parse a named color
+        let red_result = Color::parse("red");
+        let red = assert_ok_logged("parse red", red_result);
+        tracing::debug!(color = ?red, "Parsed red color");
+
+        // Parse a hex color
